/**
 * CircuitPreview — renders a circuit thumbnail using the real wokwi-element SVGs.
 *
 * Uses a HTML <div> + absolutely-positioned <img> elements (not SVG <image>),
 * because HTML <img> loads complex SVGs (xlink:href, filters, mm units) reliably
 * while SVG <image href> often fails for anything beyond simple shapes.
 *
 * Wires are drawn on an SVG overlay on top of the component images.
 *
 * SVGs are generated by scripts/generate-component-svgs.cjs at build time
 * and served from /component-svgs/ as static assets.
 *
 * Board handling:
 *  - arduino-uno examples: board IS in components[] as 'wokwi-arduino-uno'
 *  - pico / esp32 examples: board is NOT in components[] — it comes from boardType
 *    and is injected at a default position by this component
 */

import React from 'react';
import type { ExampleProject, ExampleBoard } from '../../data/examples';
import { INLINE_SVGS } from './InlineComponentSVGs';

// ── Natural display sizes (px on the simulator canvas) ──────────────────────
// A CompDef either points to a static file under /component-svgs/ (svg set) or
// to an inline React component rendered via an inline <svg> (inline set).
interface CompDef {
  svg: string; // filename under /component-svgs/ (empty string for inline)
  inline?: React.FC<{ w: number; h: number }>;
  w: number; // natural width in canvas-space pixels
  h: number; // natural height in canvas-space pixels
}

